[DataContractAttribute]
class ETGAPayLedgerJournalTableContract
{
    VendAccount orderAccount;
    PurchIdBase purchId;
    VendCurrencyCode currencyCode;
    VendDlvTermId dlvTerm;
    DataAreaId dataAreaId;
    str Vendor, VendorName, PaymentTerms, CountryOfOriginOfGoods, CountryOfFinalDestination, Reference_Number, TradeDetails;
    date InvoiceDate, PaymentDueDate, DocumentDate;
    ETGPlaceOfLoading placeOfDischarge;
    ETGPlaceOfDischarge placeOfLoading;
    str SharepointURL;


}

